const incoming = $input.first().json ?? {};
const body = incoming.body ?? incoming ?? {};

const clean = (value) => String(value ?? '').replace(/\s+/g, ' ').trim();
const toArray = (value) => {
  if (Array.isArray(value)) return value.map((item) => String(item ?? '').trim()).filter(Boolean);
  if (typeof value === 'string') return value.split(/[\n,]/).map((item) => item.trim()).filter(Boolean);
  return [];
};

const slideSeed = Array.isArray(body.cardNews?.slides) ? body.cardNews.slides : [];
const normalizedSlides = slideSeed
  .map((item, index) => ({
    slide: Number(item?.slide ?? index + 1),
    role: clean(item?.role ?? item?.key ?? `slide_${index + 1}`),
    title: clean(item?.title),
    text: clean(item?.text ?? item?.body),
  }))
  .filter((item) => item.text);

const evidencePoints = toArray(body.evidencePoints ?? body.evidence_points);
const displayName = clean(body.displayName ?? body.display_name ?? body.titleHint ?? body.externalLabel ?? body.external_label ?? body.siteName ?? body.site_name) || '시공 사례';
const hook = clean(body.hook ?? body.headlineHook ?? body.headline_hook);
const problemSummary = clean(body.problemSummary ?? body.problem_summary);
const problemDetail = clean(body.problemDetail ?? body.problem_detail);
const solutionSummary = clean(body.solutionSummary ?? body.solution_summary);
const solutionDetail = clean(body.solutionDetail ?? body.solution_detail);
const blogDraftMarkdown = String(body.blogDraftMarkdown ?? body.blog_draft_markdown ?? '').trim();
const channel = clean(body.channel).toLowerCase() || 'cardnews';

const cardNewsSeed = normalizedSlides.length > 0
  ? normalizedSlides
  : [
      { slide: 1, role: 'hook', title: displayName, text: hook || '이 공간은 무엇이 달라졌을까요?' },
      { slide: 2, role: 'problem', title: '문제 인식', text: [problemSummary, problemDetail].filter(Boolean).join('\n\n') || '현장 과제를 정리 중입니다.' },
      { slide: 3, role: 'solution', title: '해결 접근', text: [solutionSummary, solutionDetail].filter(Boolean).join('\n\n') || '적용 방향을 정리 중입니다.' },
      { slide: 4, role: 'evidence', title: '변화 포인트', text: evidencePoints.length ? evidencePoints.map((item) => `- ${item}`).join('\n') : '전후 변화와 관찰 포인트를 정리 중입니다.' },
      { slide: 5, role: 'cta', title: '온라인 쇼룸에서 더 보기', text: `${displayName} 사례처럼 우리 공간에 맞는 교육 환경 구성이 필요하다면 온라인 쇼룸에서 비슷한 사례를 더 비교해보세요.` },
    ];

return [{
  json: {
    requestSource: incoming.body ? 'webhook' : 'manual',
    contentType: clean(body.contentType ?? body.content_type) || 'showroom-case-content',
    channel,
    displayName,
    siteName: clean(body.siteName ?? body.site_name),
    externalLabel: clean(body.externalLabel ?? body.external_label) || null,
    industry: clean(body.industry) || null,
    titleHint: clean(body.titleHint ?? body.title_hint) || displayName,
    hook,
    problemSummary,
    problemDetail,
    solutionSummary,
    solutionDetail,
    evidencePoints,
    cardNewsSeed,
    blogDraftMarkdown,
    cardNewsModel: clean(body.cardNewsModel ?? body.cardnews_model ?? body.model) || 'gpt-4.1',
    blogModel: clean(body.blogModel ?? body.blog_model ?? body.model) || 'gpt-4.1',
    generatedAt: new Date().toISOString(),
  },
}];

const normalized = $('입력 정규화').first().json;
const response = $input.first().json ?? {};
const stripCodeFences = (value) => typeof value === 'string' ? value.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim() : '';
const rawContent = stripCodeFences(response.choices?.[0]?.message?.content ?? '');

let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch (error) {
  parsed = {
    master: {
      cta: `${normalized.displayName} 사례처럼 우리 공간에 맞는 구성을 온라인 쇼룸에서 더 비교해보세요.`,
      slides: normalized.cardNewsSeed.map((slide) => ({ slide: slide.slide, role: slide.role, title: slide.title, text: slide.text })),
    },
    instagram: {
      slides: normalized.cardNewsSeed.map((slide) => ({ slide: slide.slide, role: slide.role, title: slide.title, text: slide.text })),
      caption: `${normalized.displayName} 사례 핵심만 빠르게 정리했습니다.`,
    },
    facebook: {
      slides: normalized.cardNewsSeed.map((slide) => ({ slide: slide.slide, role: slide.role, title: slide.title, text: slide.text })),
      caption: `${normalized.displayName} 사례를 온라인 쇼룸 맥락으로 정리했습니다.`,
    },
  };
}

return [{
  json: {
    ok: true,
    contentType: normalized.contentType,
    channel: 'cardnews',
    displayName: normalized.displayName,
    generatedAt: new Date().toISOString(),
    payload: {
      request: {
        displayName: normalized.displayName,
        siteName: normalized.siteName,
        externalLabel: normalized.externalLabel,
        industry: normalized.industry,
      },
      cardNews: parsed,
      raw: rawContent || null,
    },
  },
}];

const normalized = $('입력 정규화').first().json;
const response = $input.first().json ?? {};
const stripCodeFences = (value) => typeof value === 'string' ? value.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim() : '';
const rawContent = stripCodeFences(response.choices?.[0]?.message?.content ?? '');

let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch (error) {
  parsed = {
    title: normalized.titleHint,
    summary: normalized.hook || '',
    body_markdown: normalized.blogDraftMarkdown || '',
    hashtags: ['#파인드가구', '#온라인쇼룸'],
    review_note: '응답 파싱 실패로 초안 원문을 fallback으로 사용했습니다.',
  };
}

return [{
  json: {
    ok: true,
    contentType: normalized.contentType,
    channel: 'blog',
    displayName: normalized.displayName,
    generatedAt: new Date().toISOString(),
    payload: {
      request: {
        displayName: normalized.displayName,
        siteName: normalized.siteName,
        externalLabel: normalized.externalLabel,
        industry: normalized.industry,
      },
      blog: parsed,
      raw: rawContent || null,
    },
  },
}];

const normalized = $('입력 정규화').first().json;
return [{
  json: {
    ok: false,
    contentType: normalized.contentType,
    channel: normalized.channel,
    error: 'unsupported_channel',
    message: 'channel must be either "cardnews" or "blog".',
    supportedChannels: ['cardnews', 'blog'],
  },
}];
